                                                <span className={`w-1.5 h-1.5 rounded-full mr-1.5 ${
                                                    application.status === 'approved' ? 'bg-green-400' : 
                                                    application.status === 'rejected' ? 'bg-red-400' : 
                                                    application.status === 'under_review' ? 'bg-blue-400' : 'bg-orange-400'
