                                                    const days = Math.floor((Date.now() - new Date(application.createdAt || Date.now())) / (1000 * 60 * 60 * 24));
                                                    return days === 0 ? t('dashboard.applicationManagement.table.today') : `${days}${t('dashboard.applicationManagement.table.daysAgo')}`;
