                                                </button>
                                            </div>
                                        ) : (
                                            <div className="flex space-x-2">
                                                <button 
                                                    className={`inline-flex items-center p-2 border border-transparent rounded-lg text-blue-600 ${isDarkMode ? 'hover:bg-blue-900/30' : 'hover:bg-blue-100'} transition-colors duration-200`}
