                                                isDarkMode 
                                                    ? 'text-white bg-gray-800 shadow' 
                                                    : `${isDarkMode ? 'text-gray-300 hover:bg-gray-600' : 'text-gray-700 hover:bg-gray-200'}`
                                            }`}
                                            onClick={() => handleThemeToggle('dark')}
                                            title="Dark Mode"
                                        >
                                            <span className="text-lg">🌙</span>
                                        </button>
                                    </div>
        
                                    {/* Online Status */}
